def breadcrumb_schema(items):
    """Generate BreadcrumbList JSON-LD. items = [(name, url), ...]"""
    entries = []
    for i, (name, url) in enumerate(items, 1):
        entries.append(f'{{"@type":"ListItem","position":{i},"name":"{name}","item":"{SITE_URL}{url}"}}')
    return f"""<script type="application/ld+json">
{{"@context":"https://schema.org","@type":"BreadcrumbList","itemListElement":[{",".join(entries)}]}}
</script>"""


def faq_schema(pairs):
    """Generate FAQPage JSON-LD. pairs = [(question, answer), ...]"""
    if not pairs:
        return ""
    entries = []
    for q, a in pairs:
        q_esc = q.replace('"', '\\"')
        a_esc = a.replace('"', '\\"').replace("\n", " ")
        entries.append(f'{{"@type":"Question","name":"{q_esc}","acceptedAnswer":{{"@type":"Answer","text":"{a_esc}"}}}}')
    return f"""<script type="application/ld+json">
{{"@context":"https://schema.org","@type":"FAQPage","mainEntity":[{",".join(entries)}]}}
</script>"""


def article_schema(title, canonical_path, description=""):
    """Generate BlogPosting JSON-LD schema."""
    t = title.replace('"', '\\"')
    d = description.replace('"', '\\"') if description else t
    return f"""<script type="application/ld+json">
{{"@context":"https://schema.org","@type":"BlogPosting","headline":"{t}","description":"{d}","author":{{"@type":"Person","name":"{AUTHOR}","description":"{AUTHOR_CREDENTIAL}","url":"https://www.linkedin.com/in/romethorndike/"}},"publisher":{{"@type":"Organization","name":"{SITE_NAME}","url":"{SITE_URL}"}},"datePublished":"{DATE_PUBLISHED}","dateModified":"{DATE_MODIFIED}","mainEntityOfPage":"{SITE_URL}{canonical_path}"}}
</script>"""


def html_head(title, description, canonical_path, og_image=None, schema=""):
    og_img = og_image or f"{SITE_URL}/assets/og-default.png"
    canonical = f"{SITE_URL}{canonical_path}"
    return f"""<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>{title}</title>
  <meta name="description" content="{description}">
  <link rel="canonical" href="{canonical}">
  <meta property="og:title" content="{title}">
  <meta property="og:description" content="{description}">
  <meta property="og:image" content="{og_img}">
  <meta property="og:url" content="{canonical}">
  <meta property="og:type" content="website">
  <meta property="og:site_name" content="{SITE_NAME}">
  <meta name="twitter:card" content="summary_large_image">
  <link rel="icon" type="image/svg+xml" href="/assets/favicon.svg">
  <link rel="icon" type="image/png" sizes="32x32" href="/assets/favicon-32.png">
  <link rel="apple-touch-icon" href="/assets/apple-touch-icon.png">
  <link rel="stylesheet" href="/assets/css/style.css?v={CSS_VERSION}">
  <!-- GA4 -->
  <script async src="https://www.googletagmanager.com/gtag/js?id=G-N0ZQVR88NY"></script>
  <script>
      window.dataLayer = window.dataLayer || [];
      function gtag(){{dataLayer.push(arguments);}}
      gtag('js', new Date());
      gtag('config', 'G-N0ZQVR88NY');
  </script>
  {schema}
</head>
<body>"""


